final:
module Shift_register_32(
   input                clk ,
   input                rst ,
   input                load,
   input [31:0]         data_in,

   output reg [31:0]    obf_Q  
);
    always@(posedge clk or posedge rst)begin
        if(rst) obf_Q <= 32'b00000000000000000000000000000000;
        else if(load) obf_Q <= data_in;
        else obf_Q <= obf_Q << 1;
    end
endmodule
